return { 
  output_name: '修改代码',
  content: '执行任务',
  values:{
    summary: input
  } 
}

if(values.worktreePath){
  await runCommand(`git worktree remove -f ${values.worktreePath}`)
}
return { content: '代码修改已完成' }

try {
  const parsed = JSON.parse(values.tasks)
  if(!Array.isArray(parsed) || parsed.some(v => typeof v !== 'string')){
    throw new Error('')
  }
  return {
    output_name:'初始化完成',
    values: { tasks: JSON.stringify(parsed, null, 2), next: '0'}
  }
} catch{
  return {
    output_name: '格式错误'
  }
}

const next = parseInt(values.next)
const tasks = JSON.parse(values.tasks)
if(next === tasks.length || tasks.length === 0){
  return {
    output_name: '验证需求',
  }
}
const current_task = tasks[next>=0 && next<tasks.length ? next: 0]
return {
  content: '执行任务',
  output_name: '执行子任务',
  values: { current_task, next: `${next + 1}` }
}
